import grpc
from concurrent import futures
import sys

from envoy.service.auth.v3 import external_auth_pb2
from envoy.service.auth.v3 import external_auth_pb2_grpc
from envoy.type.v3 import http_status_pb2
from google.rpc import status_pb2
from google.rpc import code_pb2


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, auth_config=None):
        self.auth_config = auth_config or {}
        self.authorized_tokens = self.auth_config.get('authorized_tokens', ['valid-token-123', 'admin-token-456'])
        self.required_header = self.auth_config.get('required_header', 'authorization')
        self.admin_tokens = self.auth_config.get('admin_tokens', ['admin-token-456'])
        self.admin_paths = self.auth_config.get('admin_paths', ['/admin'])

    def Check(self, request, context):
        attributes = request.attributes
        http_request = attributes.http_request
        
        headers = http_request.headers
        path = http_request.path
        method = http_request.method
        
        print(f"Authorization request: {method} {path}")
        print(f"Headers: {dict(headers)}")
        
        auth_header = headers.get(self.required_header, '')
        
        if not auth_header:
            print("Authorization denied: Missing authorization header")
            return self._create_denied_response(
                status_code=401,
                message="Missing authorization header",
                headers={'www-authenticate': 'Bearer realm="API"'}
            )
        
        token = self._extract_token(auth_header)
        
        if token not in self.authorized_tokens:
            print(f"Authorization denied: Invalid token")
            return self._create_denied_response(
                status_code=403,
                message="Invalid credentials"
            )
        
        if self._is_admin_path(path) and token not in self.admin_tokens:
            print(f"Authorization denied: Insufficient permissions for admin path")
            return self._create_denied_response(
                status_code=403,
                message="Insufficient permissions"
            )
        
        print(f"Authorization granted for token: {token[:10]}...")
        return self._create_ok_response(token, headers)

    def _extract_token(self, auth_header):
        if auth_header.lower().startswith('bearer '):
            return auth_header[7:]
        return auth_header

    def _is_admin_path(self, path):
        for admin_path in self.admin_paths:
            if path.startswith(admin_path):
                return True
        return False

    def _create_ok_response(self, token, original_headers):
        response_headers = [
            external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key='x-auth-user',
                    value=self._get_user_from_token(token)
                )
            ),
            external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key='x-auth-token',
                    value=token
                )
            ),
            external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key='x-auth-validated',
                    value='true'
                )
            )
        ]
        
        ok_response = external_auth_pb2.OkHttpResponse(
            headers=response_headers
        )
        
        return external_auth_pb2.CheckResponse(
            status=status_pb2.Status(code=code_pb2.OK),
            ok_response=ok_response
        )

    def _create_denied_response(self, status_code, message, headers=None):
        response_headers = []
        if headers:
            for key, value in headers.items():
                response_headers.append(
                    external_auth_pb2.HeaderValueOption(
                        header=external_auth_pb2.HeaderValue(
                            key=key,
                            value=value
                        )
                    )
                )
        
        denied_response = external_auth_pb2.DeniedHttpResponse(
            status=http_status_pb2.HttpStatus(code=status_code),
            headers=response_headers,
            body=message
        )
        
        return external_auth_pb2.CheckResponse(
            status=status_pb2.Status(
                code=code_pb2.PERMISSION_DENIED,
                message=message
            ),
            denied_response=denied_response
        )

    def _get_user_from_token(self, token):
        token_user_map = {
            'valid-token-123': 'user1',
            'admin-token-456': 'admin'
        }
        return token_user_map.get(token, 'unknown')


def serve(port=50051, auth_config=None):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    
    auth_service = AuthorizationService(auth_config)
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
        auth_service, server
    )
    
    server.add_insecure_port(f'[::]:{port}')
    
    print(f"Starting Envoy External Authorization Server on port {port}...")
    server.start()
    print("Server started successfully")
    
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        print("\nShutting down server...")
        server.stop(0)


